{
    "level": "A1–A2",
    "intro": "In this topic you will learn <strong>Answers to Questions</strong> - how to correctly answer different types of questions using short and full answers.",
    "rules": [
        {
            "label": "SHORT ANSWERS",
            "color": "emerald",
            "text": "<strong>Yes/No + subject + auxiliary</strong>:",
            "example": "Do you like coffee? — Yes, I do."
        },
        {
            "label": "COMPLETE ANSWERS",
            "color": "blue",
            "text": "<strong>We repeat the whole sentence</strong>:",
            "example": "Do you like coffee? Yes, I like coffee. ✅ Yes, I do."
        },
        {
            "label": "НЕ "YES/NO"",
            "color": "amber",
            "text": "<strong>Уникаємо лише "Yes"/"No"</strong> у формальному контексті:",
            "example": "❌ Yes. ✅ Yes, I do."
        }
    ]
}

{
    "title": "1. Answer types",
    "intro": "There are several ways to answer the question in English:",
    "items": [
        {
            "label": "Only Yes/No",
            "title": "Yes. / No.",
            "subtitle": "Very informal, rarely used"
        },
        {
            "label": "Short answers",
            "title": "Yes, I do. No, I don't. Short Answers with DO/DOES/DID",
            "subtitle": "Стандартні, найпоширеніші"
        },
        {
            "label": "Повні відповіді",
            "title": "Yes, I like coffee.",
            "subtitle": "Для ясності та деталізації"
        }
    ]
}

{
    "title": "2. Короткі відповіді з DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "In the Present Simple, we use <strong>do/does</strong> in the answer:",
            "examples": [
                {
                    "en": "Q: Do you like coffee? — A: Yes, I do. / No, I don't.",
                    "ua": "Question from do → answer from do"
                },
                {
                    "en": "Q: Does she work here? — A: Yes, she does. / No, she doesn't.",
                    "ua": "Question with does → answer with does"
                },
                {
                    "en": "Q: Do they know? — A: Yes, they do. / No, they don't.",
                    "ua": "We repeat the auxiliary verb"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "In Past Simple we use <strong>did</strong>:",
            "examples": [
                {
                    "en": "Q: Did you see the movie? — A: Yes, I did. / No, I didn't.",
                    "ua": "Question from did → answer from did"
                },
                {
                    "en": "Q: Did she call you? — A: Yes, she did. / No, she didn't.",
                    "ua": "Always did for all persons"
                },
                {
                    "en": "Q: Did they arrive? — A: Yes, they did. No, they didn't. auxiliary",
                    "ua": "Коротко та ясно"
                }
            ]
        },
        {
            "label": "Структура",
            "color": "purple",
            "description": "Формула короткої відповіді:",
            "examples": [
                {
                    "en": "Yes/No + Subject + do/does/did (NOT)",
                    "ua": "Так/Ні + Підмет + допоміжне"
                }
            ],
            "note": "📌 Do NOT repeat the main verb in the short answer"
        }
    ]
}

{
    "title": "3. Short answers with TO BE",
    "sections": [
        {
            "label": "Present Simple — AM/IS/ARE",
            "color": "blue",
            "description": "With <strong>to be</strong> we repeat the appropriate form:",
            "examples": [
                {
                    "en": "Q: Are you ready? — A: Yes, I am. / No, I'm not.",
                    "ua": "Question with are → answer with am (for I)"
                },
                {
                    "en": "Q: Is she happy? — A: Yes, she is. / No, she isn't.",
                    "ua": "Question with is → answer with is"
                },
                {
                    "en": "Q: Are they at home? — A: Yes, they are. / No, they aren't.",
                    "ua": "Question with are → answer with are"
                }
            ]
        },
        {
            "label": "Past Simple — WAS/WERE",
            "color": "amber",
            "description": "In the past tense we use was/were:",
            "examples": [
                {
                    "en": "Q: Were you tired? — A: Yes, I was. / No, I wasn't.",
                    "ua": "Question with were → answer with was (for I)"
                },
                {
                    "en": "Q: Was it difficult? — A: Yes, it was. / No, it wasn't.",
                    "ua": "Question from was → answer from was"
                },
                {
                    "en": "Q: Were they happy? — A: Yes, they were. No, they weren't. (NOT: No, I am not.)",
                    "ua": "Питання з were → відповідь з were"
                }
            ]
        },
        {
            "label": "Скорочення",
            "color": "rose",
            "description": "У негативних коротких відповідях зазвичай використовуємо скорочення:",
            "examples": [
                {
                    "en": "No, I'm not. (NOT: No, I am not.)",
                    "ua": "The shortened form is more natural"
                },
                {
                    "en": "No, she isn't. / No, she's not.",
                    "ua": "Both options are correct"
                },
                {
                    "en": "No, they aren't. No, they're not. Short answers with modal verbs",
                    "ua": "Скорочення у розмові"
                }
            ],
            "note": "📌 У позитивних відповідях зазвичай повна форма: Yes, I am."
        }
    ]
}

{
    "title": "4. Короткі відповіді з модальними дієсловами",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "With <strong>can/could</strong> we repeat the modal in the answer:",
            "examples": [
                {
                    "en": "Q: Can you swim? — A: Yes, I can. / No, I can't.",
                    "ua": "Question from can → answer from can"
                },
                {
                    "en": "Q: Could she help? — A: Yes, she could. No, she couldn't. — A: Yes, I will. / No, I won't.",
                    "ua": "Питання з could → відповідь з could"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "З <strong>will/would</strong> також повторюємо:",
            "examples": [
                {
                    "en": "Q: Will you come? — A: Yes, I will. / No, I won't.",
                    "ua": "Question from will → answer from will"
                },
                {
                    "en": "Q: Would you like coffee? — A: Yes, I would. / No, I wouldn't.",
                    "ua": "Question with would → answer with would"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "purple",
            "description": "Other modals work according to the same principle:",
            "examples": [
                {
                    "en": "Q: Should we go? — A: Yes, we should. / No, we shouldn't.",
                    "ua": "We repeat should"
                },
                {
                    "en": "Q: Must I wait? — A: Yes, you must. / No, you needn't.",
                    "ua": "Must or needn't in the negative form"
                }
            ],
            "note": "📌 Structure: Yes/No + Subject + Modal"
        }
    ]
}

{
    "title": "5. Short answers with HAVE/HAS",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "In Present Perfect we also use have/has:",
            "examples": [
                {
                    "en": "Q: Have you seen it? — A: Yes, I have. / No, I haven't.",
                    "ua": "Question from have → answer from have"
                },
                {
                    "en": "Q: Has she finished? — A: Yes, she has. No, she hasn't. — A: Yes, I have. / No, I haven't.",
                    "ua": "Питання з has → відповідь з has"
                }
            ]
        },
        {
            "label": "HAVE GOT",
            "color": "blue",
            "description": "З <strong>have got</strong> повторюємо have/has:",
            "examples": [
                {
                    "en": "Q: Have you got a car? — A: Yes, I have. / No, I haven't.",
                    "ua": "Question from have → answer from have"
                },
                {
                    "en": "Q: Has she got a dog? — A: Yes, she has. No, she hasn't. — A: Yes, I do. / No, I don't.",
                    "ua": "Питання з has → відповідь з has"
                }
            ]
        },
        {
            "label": "Американський варіант",
            "color": "rose",
            "description": "В американському варіанті з <strong>have</strong> (володіння) часто do:",
            "examples": [
                {
                    "en": "Q: Do you have a car? — A: Yes, I do. / No, I don't.",
                    "ua": "American version"
                }
            ],
            "note": "📌 British version: have got, American version: have with do"
        }
    ]
}

{
    "title": "6. Short answers with other tenses",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "In Present Continuous we use am/is/are:",
            "examples": [
                {
                    "en": "Q: Are you working? — A: Yes, I am. / No, I'm not.",
                    "ua": "Reply from am/is/are"
                },
                {
                    "en": "Q: Is she coming? — A: Yes, she is. / No, she isn't.",
                    "ua": "We repeat to be"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "sky",
            "description": "In Past Continuous we use was/were:",
            "examples": [
                {
                    "en": "Q: Were you sleeping? — A: Yes, I was. / No, I wasn't.",
                    "ua": "Answer with was/were"
                },
                {
                    "en": "Q: Was she studying? — A: Yes, she was. No, she wasn't. do/does/did",
                    "ua": "Повторюємо was/were"
                }
            ]
        },
        {
            "label": "Загальне правило",
            "color": "purple",
            "description": "У короткій відповіді завжди повторюємо допоміжне дієслово з питання:",
            "examples": [
                {
                    "en": "Do → do/does/did",
                    "ua": "Повторюємо do/does/did"
                },
                {
                    "en": "To be → am/is/are/was/were",
                    "ua": "We repeat the form to be"
                },
                {
                    "en": "Modal → can/will/should...",
                    "ua": "We repeat the modal"
                }
            ],
            "note": "📌 Short answers = Yes/No + Subject + Auxiliary"
        }
    ]
}

{
    "title": "7. Full answers",
    "sections": [
        {
            "label": "When to use",
            "color": "blue",
            "description": "Full answers are used for <strong>clarity</strong> or <strong>additional information</strong>:",
            "examples": [
                {
                    "en": "Q: Do you like coffee? — A: Yes, I like coffee very much.",
                    "ua": "Adding details"
                },
                {
                    "en": "Q: Did she call? — A: Yes, she called me this morning.",
                    "ua": "Adding time"
                },
                {
                    "en": "Q: Are they coming? — A: No, they aren't coming. They're busy.",
                    "ua": "We explain the reason"
                }
            ]
        },
        {
            "label": "Structure",
            "color": "amber",
            "description": "In the complete answer, we repeat the entire sentence:",
            "examples": [
                {
                    "en": "Q: Do you work here? — A: Yes, I work here.",
                    "ua": "Complete sentence"
                },
                {
                    "en": "Q: Is she a teacher? — A: Yes, she is a teacher.",
                    "ua": "The whole sentence"
                },
                {
                    "en": "Q: Can you swim? A: No, I can't swim. — A: Yes, I do. I speak English and French.",
                    "ua": "Повна форма"
                }
            ]
        },
        {
            "label": "Комбінація",
            "color": "emerald",
            "description": "Часто комбінуємо коротку і повну відповідь:",
            "examples": [
                {
                    "en": "Q: Do you speak English? — A: Yes, I do. I speak English and French.",
                    "ua": "Brief + additional information"
                },
                {
                    "en": "Q: Did you like the movie? — A: No, I didn't. It was too long.",
                    "ua": "Short + explanation"
                }
            ],
            "note": "📌 Short answer + additional information = natural conversation"
        }
    ]
}

{
    "title": "8. Answers to Wh-questions",
    "sections": [
        {
            "label": "Specific information",
            "color": "purple",
            "description": "We do NOT answer Yes/No to Wh-questions, but give specific information:",
            "examples": [
                {
                    "en": "Q: What do you like? — A: I like coffee. (NOT: Yes)",
                    "ua": "We answer the question "what""
                },
                {
                    "en": "Q: Where do you live? — A: I live in Kyiv.",
                    "ua": "We answer the question "where""
                },
                {
                    "en": "Q: When did you arrive? A: I arrived yesterday. — A: From Ukraine. / I'm from Ukraine.",
                    "ua": "Відповідаємо на питання "коли""
                }
            ]
        },
        {
            "label": "Короткі відповіді на Wh-питання",
            "color": "sky",
            "description": "Можна відповідати коротко без повного речення:",
            "examples": [
                {
                    "en": "Q: Where are you from? — A: From Ukraine. / I'm from Ukraine.",
                    "ua": "Short or full"
                },
                {
                    "en": "Q: What time is it? — A: 5 o'clock. / It's 5 o'clock.",
                    "ua": "Both options are OK"
                },
                {
                    "en": "Q: Who is she? — A: My sister. / She's my sister.",
                    "ua": "Short or full"
                }
            ],
            "note": "📌 For Wh-questions we give specific information, not Yes/No"
        }
    ]
}

{
    "title": "9. Quick answer table",
    "intro": "How to form short answers with different verbs:",
    "rows": [
        {
            "en": "DO/DOES/DID",
            "ua": "Simple tenses",
            "note": "Yes, I do. / No, I don't. (does/doesn't, did/didn't)"
        },
        {
            "en": "TO BE",
            "ua": "Verb to be",
            "note": "Yes, I am. / No, I'm not. (is/isn't, are/aren't)"
        },
        {
            "en": "MODALS",
            "ua": "Modal verbs",
            "note": "Yes, I can. / No, I can't. (will/won't, should/shouldn't)"
        },
        {
            "en": "HAVE/HAS",
            "ua": "Have got, Perfect",
            "note": "Yes, I have. / No, I haven't. (has/hasn't)"
        },
        {
            "en": "CONTINUOUS",
            "ua": "Continuous times",
            "note": "Yes, I am. / No, I'm not. (is/isn't, are/aren't)"
        }
    ],
    "warning": "📌 Basic rule: <strong>we repeat the auxiliary verb from the question</strong>"
}

{
    "title": "10. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Only Yes/No without auxiliary verb.",
            "wrong": "❌ Q: Do you like it? A: Yes. (incomplete answer)",
            "right": " ✅ <span class="font-mono">Q: Do you like it? A: Yes, I do.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Repetition of the main verb in the short answer.",
            "wrong": "❌ Q: Do you like it? A: Yes, I like.",
            "right": "​​​​ <span class="font-mono">Q: Do you like it? A: Yes, I do.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Wrong auxiliary verb in the answer.",
            "wrong": "❌ Q: Can you swim? A: Yes, I do.",
            "right": "​​​​ <span class="font-mono">Q: Can you swim? A: Yes, I can.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Yes/No on Wh-question.",
            "wrong": "❌ Q: Where do you live? A: Yes, in Kyiv.",
            "right": " ✅ <span class="font-mono">Q: Where do you live? A: In Kyiv. / I live in Kyiv.</span>"
        }
    ]
}

{
    "title": "12. Practice",
    "select_title": "Exercise 1. Choose the correct answer",
    "select_intro": "Choose the correct short answer to the question.",
    "selects": [
        {
            "label": "Q: Do you like coffee? A: (Yes / Yes, I like / Yes, I do)",
            "prompt": "Which answer is correct?"
        },
        {
            "label": "Q: Is she happy? A: (Yes / Yes, she happy / Yes, she is)",
            "prompt": "Which answer is correct?"
        },
        {
            "label": "Q: Can you swim? A: (Yes / Yes, I swim / Yes, I can)",
            "prompt": "Which answer is correct?"
        },
        {
            "label": "Q: Did they come? A: (No / No, they came / No, they didn't)",
            "prompt": "Which answer is correct?"
        }
    ],
    "options": [
        "First option",
        "Second option",
        "Third option"
    ],
    "input_title": "Exercise 2. Give a short answer",
    "input_intro": "Give the correct short answer to the question.",
    "inputs": [
        {
            "before": "Q: Do you do you speak English? A: Yes, ",
            "after": "."
        },
        {
            "before": "Q: Is she a teacher? A: No, ",
            "after": "."
        },
        {
            "before": "Q: Can they help? A: Yes, ",
            "after": "."
        },
        {
            "before": "Q: Did you see it? A: No. A: Yes.",
            "after": "."
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку у відповіді.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "Q: Do you like it? A: Yes.",
            "example_target": "Q: Do you like it? A: Yes, I do."
        },
        {
            "original": "Q: Can you swim? A: Yes, I do.",
            "placeholder": "Fix the error"
        },
        {
            "original": "Q: Is she happy? A: Yes, she happy.",
            "placeholder": "Fix the error"
        },
        {
            "original": "Q: Do you like it? A: Yes I like. questions",
            "placeholder": "Виправ помилку"
        }
    ]
}

